"use client";

import type { HTMLAttributes, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { DialogKeyboardHints, type KeyboardHint } from "./dialog-keyboard-hints";

export { DialogKeyboardHints, type KeyboardHint };

export interface DialogFooterProps extends HTMLAttributes<HTMLDivElement> {
  hints?: KeyboardHint[];
  children?: ReactNode;
}

function DialogFooterRoot({ hints, className, children, ...props }: DialogFooterProps) {
  const hasHints = hints && hints.length > 0;

  return (
    <div
      className={cn(
        "flex gap-3 items-center px-4 pb-4 border-x border-b shrink-0 bg-background text-foreground border-border",
        hasHints ? "justify-between" : "justify-end",
        className
      )}
      {...props}
    >
      {hasHints ? <DialogKeyboardHints hints={hints} /> : null}
      {children ? <DialogFooterActions>{children}</DialogFooterActions> : null}
    </div>
  );
}

export type DialogFooterActionsProps = HTMLAttributes<HTMLDivElement>;

function DialogFooterActions({ className, ...props }: DialogFooterActionsProps) {
  return (
    <div className={cn("flex shrink-0 items-center justify-end gap-3", className)} {...props} />
  );
}

export const DialogFooter: typeof DialogFooterRoot & {
  Hints: typeof DialogKeyboardHints;
  Actions: typeof DialogFooterActions;
} = Object.assign(DialogFooterRoot, {
  Hints: DialogKeyboardHints,
  Actions: DialogFooterActions,
});

"use client";

import type { HTMLAttributes } from "react";
import { Kbd } from "../kbd/kbd";
import { cn } from "@/lib/utils";

export interface KeyboardHint {
  key: string;
  label: string;
}

export interface DialogKeyboardHintsProps extends HTMLAttributes<HTMLDivElement> {
  hints: KeyboardHint[];
  size?: "sm" | "md";
}

export function DialogKeyboardHints({ hints, size = "md", className, ...props }: DialogKeyboardHintsProps) {
  if (!hints.length) return null;

  return (
    <div
      className={cn("flex min-w-0 flex-wrap items-center gap-x-3 gap-y-1 text-xs", className)}
      {...props}
    >
      {hints.map((hint) => (
        <span key={`${hint.key}-${hint.label}`} className="inline-flex items-center gap-1">
          <Kbd size={size} aria-hidden="true">{hint.key}</Kbd>
          <span>{hint.label}</span>
        </span>
      ))}
    </div>
  );
}

"use client";

import type { ReactNode, MouseEventHandler, FocusEventHandler, Ref } from "react";
import { useDialogDismiss } from "./dialog-context";
import { Button, type ButtonProps } from "../button/button";

export interface DialogCloseProps
  extends Pick<ButtonProps, "variant" | "size" | "bracket" | "className" | "disabled" | "highlighted"> {
  children?: ReactNode;
  onClick?: MouseEventHandler<HTMLButtonElement>;
  onFocus?: FocusEventHandler<HTMLButtonElement>;
  ref?: Ref<HTMLButtonElement>;
  autoFocus?: boolean;
  [dataAttribute: `data-${string}`]: unknown;
}

export function DialogClose({
  children,
  onClick,
  variant = "ghost",
  ref,
  ...buttonProps
}: DialogCloseProps) {
  const handleClick = useDialogDismiss(onClick);

  return (
    <Button
      ref={ref}
      type="button"
      {...buttonProps}
      variant={variant}
      aria-label={!children ? "Close dialog" : undefined}
      onClick={handleClick}
    >
      {children ?? "[x]"}
    </Button>
  );
}

"use client";

import type { ReactNode, MouseEventHandler, FocusEventHandler, Ref } from "react";
import { useDialogDismiss } from "./dialog-context";
import { Button, type ButtonProps } from "../button/button";

export interface DialogActionProps
  extends Pick<ButtonProps, "variant" | "size" | "bracket" | "className" | "disabled" | "loading" | "highlighted"> {
  children: ReactNode;
  onClick?: MouseEventHandler<HTMLButtonElement>;
  onFocus?: FocusEventHandler<HTMLButtonElement>;
  ref?: Ref<HTMLButtonElement>;
  autoFocus?: boolean;
  [dataAttribute: `data-${string}`]: unknown;
}

export function DialogAction({
  children,
  onClick,
  variant = "action",
  bracket = true,
  ref,
  ...props
}: DialogActionProps) {
  const handleClick = useDialogDismiss(onClick);

  return (
    <Button ref={ref} type="button" {...props} variant={variant} bracket={bracket} onClick={handleClick}>
      {children}
    </Button>
  );
}

"use client";

import {
  cloneElement,
  isValidElement,
  type ComponentPropsWithRef,
  type ReactElement,
  type ReactNode,
  type MouseEventHandler,
  type Ref,
  type RefCallback,
} from "react";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { useDialogContext } from "./dialog-context";

export interface DialogTriggerRenderProps {
  ref: RefCallback<HTMLElement>;
  className?: string;
  "aria-haspopup": "dialog";
  "aria-expanded": boolean;
  "aria-controls": string;
  onClick: MouseEventHandler<HTMLElement>;
}

export interface DialogTriggerProps {
  children: ReactNode | ((props: DialogTriggerRenderProps) => ReactNode);
  className?: string;
  onClick?: MouseEventHandler<HTMLElement>;
  ref?: Ref<HTMLElement>;
}

interface DialogTriggerElementProps {
  ref?: Ref<HTMLElement>;
  className?: string;
  type?: string;
  "aria-haspopup"?: "dialog";
  "aria-expanded"?: boolean;
  "aria-controls"?: string;
  onClick?: MouseEventHandler<HTMLElement>;
}

const nativeInteractiveElements = new Set(["button", "a", "input", "select", "textarea", "summary"]);

function isNativeInteractiveElement(element: ReactElement<DialogTriggerElementProps>): boolean {
  return typeof element.type === "string" && nativeInteractiveElements.has(element.type);
}

function mergeClickHandlers(
  existing: MouseEventHandler<HTMLElement> | undefined,
  added: MouseEventHandler<HTMLElement>,
): MouseEventHandler<HTMLElement> {
  return (event) => {
    existing?.(event);
    if (!event.defaultPrevented) added(event);
  };
}

export function DialogTrigger({ children, className, onClick, ref }: DialogTriggerProps) {
  const { open, onOpenChange, contentId, triggerRef } = useDialogContext();
  const composedRef = composeRefs(triggerRef, ref);

  const handleClick: MouseEventHandler<HTMLElement> = (e) => {
    onClick?.(e);
    if (!e.defaultPrevented) onOpenChange(true);
  };

  const triggerProps: DialogTriggerRenderProps = {
    ref: composedRef,
    className,
    "aria-haspopup": "dialog",
    "aria-expanded": open,
    "aria-controls": contentId,
    onClick: handleClick,
  };

  if (typeof children === "function") return <>{children(triggerProps)}</>;

  if (isValidElement<DialogTriggerElementProps>(children)) {
    const child = children as ReactElement<DialogTriggerElementProps>;
    if (isNativeInteractiveElement(child)) {
      const buttonType = child.type === "button" ? { type: child.props.type ?? "button" } : {};

      return cloneElement(child, {
        ...buttonType,
        ref: composeRefs(composedRef, child.props.ref),
        className: cn(child.props.className, className),
        "aria-haspopup": triggerProps["aria-haspopup"],
        "aria-expanded": triggerProps["aria-expanded"],
        "aria-controls": triggerProps["aria-controls"],
        onClick: mergeClickHandlers(child.props.onClick, triggerProps.onClick),
      });
    }
  }

  const buttonProps = triggerProps satisfies ComponentPropsWithRef<"button">;
  return (
    <button type="button" {...buttonProps}>
      {children}
    </button>
  );
}
